#include <iostream>
#include <map>
using namespace std;
map<string,int> mmap;
int main()
{
    int n;
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        string o;
        cin>>o;
        mmap[o]=0;
    }
    int m;
    cin>>m;
    for(int i=1;i<=m;i++)
    {
        string o;
        cin>>o;
        if(mmap.count(o)==false)
        {
            cout<<"WRONG"<<endl;
        }
        else if(mmap[o]==0)
        {
            cout<<"OK"<<endl;
            mmap[o]++;
        }
        else
        {
            cout<<"REPEAT"<<endl;
        }
    }
    return 0;
}
